SELECT i.*, s.supplier_name AS supplier FROM ingredients i LEFT JOIN suppliers s ON i.supplier_id = s.id
AND i.category = #{category}
AND i.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY FIELD(i.category,'원두','유제품','시럽/소스','파우더','차류','소모품','기타'), i.name LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM ingredients i


        AND i.category = #{category}


        AND i.name LIKE CONCAT('%', #{keyword}, '%')

SELECT * FROM ingredients
WHERE supplier_id = #{supplierId}
ORDER BY FIELD(category,'원두','유제품','시럽/소스','파우더','차류','소모품','기타'), name
